svg.script:
(function () {
  try {
    var svg = document.querySelector('svg');
    var outer = document.getElementById('mouseGlowOuter');
    var drift = document.getElementById('glowDrift');
    var curX = 800, curY = 200, targetX = 800, targetY = 200, tracking = false;

    function toLocal(evt) {
      var rect = svg.getBoundingClientRect();
      var x = (evt.clientX - rect.left) * (1600 / rect.width);
      var y = (evt.clientY - rect.top) * (400 / rect.height);
      return [x, y];
    }

    svg.addEventListener('mousemove', function (evt) {
      if (!tracking && drift && drift.parentNode) {
        drift.parentNode.removeChild(drift);
        tracking = true;
      }
      var p = toLocal(evt);
      targetX = p[0];
      targetY = p[1];
    });

    function raf() {
      curX += (targetX - curX) * 0.08;
      curY += (targetY - curY) * 0.08;
      if (tracking) {
        outer.setAttribute('transform', 'translate(' + curX.toFixed(1) + ',' + curY.toFixed(1) + ')');
      }
      requestAnimationFrame(raf);
    }
    requestAnimationFrame(raf);
  } catch (e) { /* no-op fallback: SMIL drift keeps running */ }
})();
